def valid_sudoku_3x3(grid):
    if len(grid) != 3:
        return False
    for row in grid:
        if len(row) != 3:
            return False
    seen = set()
    for row in grid:
        for cell in row:
            if cell < 1 or cell > 9:
                return False
            if cell in seen:
                return False
            seen.add(cell)
    return True
